#include <stdio.h>
#include <stdlib.h>

typedef struct Node {
    int val;
    int cnt;
    struct Node *next;
} Node;

#define TABLE_SIZE 200003

static Node *table[TABLE_SIZE];

static unsigned int hash_int(int x) {
    return ((unsigned int)x * 2654435761u) % TABLE_SIZE;
}

static void add(int x) {
    unsigned int h = hash_int(x);
    Node *p = table[h];
    while (p) {
        if (p->val == x) { p->cnt++; return; }
        p = p->next;
    }
    Node *newNode = (Node*)malloc(sizeof(Node));
    newNode->val = x; newNode->cnt = 1; newNode->next = table[h];
    table[h] = newNode;
}

static void clear_table() {
    for (int i = 0; i < TABLE_SIZE; ++i) {
        Node *p = table[i];
        while (p) {
            Node *tmp = p; p = p->next; free(tmp);
        }
        table[i] = NULL;
    }
}

int main() {
    int T; if (scanf("%d", &T)!=1) return 0;
    while (T--) {
        int N; long long W, Wr; scanf("%d %lld %lld", &N, &W, &Wr);
        if (Wr >= W) {
            // consume the line of weights
            for (int i = 0; i < N; ++i) { int tmp; scanf("%d", &tmp); }
            printf("YES\n");
            continue;
        }
        for (int i = 0; i < N; ++i) {
            int w; scanf("%d", &w);
            add(w);
        }
        long long added = 0;
        for (int i = 0; i < TABLE_SIZE; ++i) {
            for (Node *p = table[i]; p; p = p->next) {
                long long pairs = p->cnt / 2;
                added += pairs * 2LL * p->val;
            }
        }
        clear_table();
        if (Wr + added >= W) printf("YES\n"); else printf("NO\n");
    }
    return 0;
}

