import java.io.*;
import java.util.*;

public class Main {
    public static void main(String[] args) throws Exception {
        FastScanner fs = new FastScanner(System.in);
        int T = fs.nextInt();
        StringBuilder sb = new StringBuilder();
        while (T-- > 0) {
            int N = fs.nextInt();
            long W = fs.nextLong();
            long Wr = fs.nextLong();
            int[] arr = new int[N];
            for (int i = 0; i < N; i++) arr[i] = fs.nextInt();
            if (Wr >= W) {
                sb.append("YES\n");
                continue;
            }
            HashMap<Integer, Integer> map = new HashMap<>(N * 2);
            for (int v : arr) map.put(v, map.getOrDefault(v, 0) + 1);
            long added = 0;
            for (Map.Entry<Integer, Integer> e : map.entrySet()) {
                long pairs = e.getValue() / 2;
                added += pairs * 2L * e.getKey();
            }
            sb.append(Wr + added >= W ? "YES" : "NO").append('\n');
        }
        System.out.print(sb.toString());
    }

    // Fast scanner for large input
    static class FastScanner {
        private final InputStream in;
        private final byte[] buffer = new byte[1 << 16];
        private int ptr = 0, len = 0;
        FastScanner(InputStream in) { this.in = in; }
        private int readByte() throws IOException {
            if (ptr >= len) {
                len = in.read(buffer);
                ptr = 0;
                if (len <= 0) return -1;
            }
            return buffer[ptr++];
        }
        int nextInt() throws IOException { return (int) nextLong(); }
        long nextLong() throws IOException {
            int c; do { c = readByte(); } while (c <= ' ');
            boolean neg = false;
            if (c == '-') { neg = true; c = readByte(); }
            long val = 0;
            while (c > ' ') {
                val = val * 10 + (c - '0');
                c = readByte();
            }
            return neg ? -val : val;
        }
    }
}

